// src/pages/ServicesPage.jsx  –  Full-featured: cart, checkout, Aadhaar modals, sale/discount view
import { useState, useEffect } from "react"
import { useNavigate, useLocation } from "react-router-dom"
import { auth } from "../firebase"
import { supabase } from "../lib/supabase"
import CartPage, { useCart } from "./CartPage"
import CheckoutPage from "./CheckoutPage"

/* ─── data ─────────────────────────────────────────────────────────────────── */
const MEDICINE_CATEGORIES = [
  { id: "prescription", emoji: "💊", label: "Prescription", sub: "Upload & order", color: "#eef3e4", accent: "#5a6e3a" },
  { id: "otc", emoji: "🧴", label: "OTC / General", sub: "No Rx needed", color: "#e8f4f0", accent: "#2cb89a" },
  { id: "ayurveda", emoji: "🌿", label: "Ayurveda", sub: "Herbal range", color: "#fdf6e8", accent: "#c88010" },
  { id: "vitamins", emoji: "⚡", label: "Vitamins", sub: "Supplements", color: "#f0edfd", accent: "#8b6fcb" },
  { id: "devices", emoji: "🩺", label: "Devices", sub: "BP, sugar…", color: "#fdeaea", accent: "#e05252" },
  { id: "personal", emoji: "🧼", label: "Personal Care", sub: "Hygiene range", color: "#e8f4f0", accent: "#2cb89a" },
]

const UTILITY_ITEMS = [
  { id: "recharge", emoji: "📱", label: "Mobile Recharge", sub: "Prepaid & postpaid", color: "#fdf6e8", accent: "#c88010" },
  { id: "dth", emoji: "📺", label: "DTH / Cable", sub: "Top-up instantly", color: "#eef3e4", accent: "#5a6e3a" },
  { id: "electric", emoji: "⚡", label: "Electricity", sub: "Pay bill online", color: "#fdeaea", accent: "#e05252" },
  { id: "water", emoji: "💧", label: "Water Bill", sub: "Municipal boards", color: "#e8f4f0", accent: "#2cb89a" },
  { id: "gas", emoji: "🔥", label: "Gas / LPG", sub: "Book cylinder", color: "#fdf6e8", accent: "#c88010" },
  { id: "broadband", emoji: "🌐", label: "Broadband", sub: "ISP payments", color: "#f0edfd", accent: "#8b6fcb" },
  { id: "banking", emoji: "🏦", label: "Banking", sub: "Transfer & pay", color: "#eef3e4", accent: "#5a6e3a" },
  { id: "insurance", emoji: "🛡️", label: "Insurance", sub: "Health & term", color: "#e8f4f0", accent: "#2cb89a" },
]

const AADHAR_ITEMS = [
  { id: "update", emoji: "✏️", label: "Update Aadhaar", sub: "Name, DOB, address", badge: "UIDAI", color: "#eef3e4", accent: "#5a6e3a" },
  { id: "download", emoji: "📥", label: "Download e-Aadhaar", sub: "PDF from UIDAI", badge: "Free", color: "#e8f4f0", accent: "#2cb89a" },
  { id: "link", emoji: "🔗", label: "Link to Mobile", sub: "OTP verification", badge: "Secure", color: "#fdf6e8", accent: "#c88010" },
  { id: "verify", emoji: "✅", label: "Verify Aadhaar", sub: "Instant check", badge: "UIDAI", color: "#eef3e4", accent: "#5a6e3a" },
]

const DOCUMENT_ITEMS = [
  { id: "pan", emoji: "💳", label: "PAN Card", sub: "Link & verify", status: "linked", color: "#eef3e4", accent: "#5a6e3a" },
  { id: "abha", emoji: "🏥", label: "ABHA Health ID", sub: "National health ID", status: "link", color: "#e8f4f0", accent: "#2cb89a" },
  { id: "driving", emoji: "🚗", label: "Driving Licence", sub: "DigiLocker sync", status: "link", color: "#fdf6e8", accent: "#c88010" },
  { id: "voter", emoji: "🗳️", label: "Voter ID", sub: "Election Commission", status: "linked", color: "#f0edfd", accent: "#8b6fcb" },
  { id: "passport", emoji: "📘", label: "Passport", sub: "Travel documents", status: "link", color: "#fdeaea", accent: "#e05252" },
  { id: "cowin", emoji: "💉", label: "CoWin / Vacc.", sub: "Vaccination records", status: "linked", color: "#e8f4f0", accent: "#2cb89a" },
]

const TABS = [
  { id: "medicine", label: "Medicine", emoji: "💊" },
  { id: "utilities", label: "Utilities", emoji: "⚡" },
  { id: "aadhaar", label: "Aadhaar", emoji: "🇮🇳" },
  { id: "documents", label: "Documents", emoji: "📋" },
]

const COMMON_PRESCRIPTION_MEDS = [
  { name: "Amoxicillin", dosage: "500mg", price: 85, originalPrice: 170, emoji: "💊" },
  { name: "Azithromycin", dosage: "250mg", price: 120, originalPrice: 240, emoji: "💊" },
  { name: "Metformin", dosage: "500mg", price: 45, originalPrice: 90, emoji: "💊" },
  { name: "Atorvastatin", dosage: "10mg", price: 95, originalPrice: 190, emoji: "💊" },
  { name: "Omeprazole", dosage: "20mg", price: 55, originalPrice: 110, emoji: "💊" },
  { name: "Amlodipine", dosage: "5mg", price: 65, originalPrice: 130, emoji: "💊" },
  { name: "Ciprofloxacin", dosage: "500mg", price: 110, originalPrice: 220, emoji: "💊" },
  { name: "Pantoprazole", dosage: "40mg", price: 75, originalPrice: 150, emoji: "💊" },
]

const OTC_MEDS = [
  { name: "Paracetamol", dosage: "500mg", price: 25, originalPrice: 50, emoji: "🧴" },
  { name: "Ibuprofen", dosage: "400mg", price: 35, originalPrice: 70, emoji: "🧴" },
  { name: "Cetirizine", dosage: "10mg", price: 30, originalPrice: 60, emoji: "🧴" },
  { name: "Antacid Syrup", dosage: "15ml", price: 60, originalPrice: 120, emoji: "🧴" },
  { name: "Vitamin C", dosage: "500mg", price: 50, originalPrice: 100, emoji: "🍊" },
  { name: "Cough Syrup", dosage: "100ml", price: 90, originalPrice: 180, emoji: "🧴" },
  { name: "Betadine", dosage: "30ml", price: 70, originalPrice: 140, emoji: "🟤" },
  { name: "Antifungal Cream", dosage: "15g", price: 80, originalPrice: 160, emoji: "🧴" },
]

/* ─── Aadhaar Modal ─────────────────────────────────────────────────────────── */
function AadhaarActionModal({ item, onClose }) {
  const [step, setStep] = useState("form")
  const [aadhaarNum, setNum] = useState("")
  const [mobile, setMobile] = useState("")
  const [otp, setOtp] = useState("")
  const [file, setFile] = useState(null)
  const [loading, setLoading] = useState(false)
  const [done, setDone] = useState(false)

  const simulate = async (label) => {
    setLoading(true)
    await new Promise(r => setTimeout(r, 1800))
    setLoading(false)
    setDone(true)
  }

  const btnStyle = (bg = "#5a6e3a") => ({
    width: "100%", background: `linear-gradient(135deg,${bg},${bg}cc)`, color: "#fff",
    border: "none", borderRadius: 14, padding: "14px", fontSize: 14, fontWeight: 900,
    cursor: loading ? "default" : "pointer", fontFamily: "'Nunito',sans-serif",
    opacity: loading ? 0.7 : 1, marginTop: 10
  })

  const inputStyle = {
    width: "100%", boxSizing: "border-box", background: "#fff",
    border: "1.5px solid #d8e8c0", borderRadius: 12, padding: "12px 14px",
    fontSize: 14, fontWeight: 600, fontFamily: "'Nunito',sans-serif",
    color: "#1e2a12", outline: "none", marginBottom: 10
  }

  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, zIndex: 3000, background: "rgba(0,0,0,0.55)", display: "flex", alignItems: "flex-end", justifyContent: "center" }}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#f5f2eb", borderRadius: "26px 26px 0 0", width: "100%", maxWidth: 480,
        padding: "0 0 30px", boxShadow: "0 -8px 44px rgba(0,0,0,0.2)", fontFamily: "'Nunito',sans-serif"
      }}>
        {/* Header */}
        <div style={{ background: `linear-gradient(135deg,${item.accent},${item.accent}aa)`, borderRadius: "26px 26px 0 0", padding: "16px 20px", display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{ width: 44, height: 44, borderRadius: 14, background: "rgba(255,255,255,0.2)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22 }}>{item.emoji}</div>
          <div style={{ flex: 1 }}>
            <div style={{ color: "#fff", fontWeight: 900, fontSize: 16 }}>{item.label}</div>
            <div style={{ color: "rgba(255,255,255,0.65)", fontSize: 11 }}>{item.sub}</div>
          </div>
          <button onClick={onClose} style={{ background: "rgba(255,255,255,0.18)", border: "none", borderRadius: 10, width: 34, height: 34, color: "#fff", fontSize: 16, cursor: "pointer" }}>✕</button>
        </div>

        <div style={{ padding: "20px 20px 0" }}>
          {done ? (
            <div style={{ textAlign: "center", padding: "30px 0" }}>
              <div style={{ fontSize: 60, marginBottom: 12 }}>✅</div>
              <div style={{ fontWeight: 900, fontSize: 18, color: "#1e2a12", marginBottom: 6 }}>{item.label} Successful!</div>
              <div style={{ fontSize: 13, color: "#6a7a5a" }}>Your request has been processed.</div>
              <button onClick={onClose} style={{ ...btnStyle(), marginTop: 20, width: "auto", padding: "12px 32px" }}>Done</button>
            </div>
          ) : (

            <>
              {/* UPLOAD AADHAAR */}
              {item.id === "download" && (
                <>
                  <p style={{ fontSize: 13, color: "#6a7a5a", marginBottom: 14 }}>Enter your Aadhaar number to download the e-Aadhaar PDF from UIDAI.</p>
                  <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase" }}>Aadhaar Number</label>
                  <input value={aadhaarNum} onChange={e => setNum(e.target.value.replace(/\D/g, "").slice(0, 12))} placeholder="XXXX XXXX XXXX" style={{ ...inputStyle, marginTop: 6 }} />
                  {!otp ? (
                    <button onClick={() => { if (aadhaarNum.length === 12) setOtp("sent") }} style={btnStyle()}>Send OTP to Registered Mobile</button>
                  ) : (
                    <>
                      <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase", display: "block", marginTop: 10 }}>Enter OTP</label>
                      <input placeholder="6-digit OTP" style={{ ...inputStyle, marginTop: 6 }} />
                      <button onClick={() => simulate("Download")} style={btnStyle()}>
                        {loading ? "Downloading…" : "📥 Download e-Aadhaar PDF"}
                      </button>
                    </>
                  )}
                </>
              )}

              {/* LINK TO MOBILE */}
              {item.id === "link" && (
                <>
                  <p style={{ fontSize: 13, color: "#6a7a5a", marginBottom: 14 }}>Link your Aadhaar with your mobile number via OTP verification.</p>
                  <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase" }}>Aadhaar Number</label>
                  <input value={aadhaarNum} onChange={e => setNum(e.target.value.replace(/\D/g, "").slice(0, 12))} placeholder="XXXX XXXX XXXX" style={{ ...inputStyle, marginTop: 6 }} />
                  <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase" }}>New Mobile Number</label>
                  <input value={mobile} onChange={e => setMobile(e.target.value.replace(/\D/g, "").slice(0, 10))} placeholder="10-digit mobile" style={{ ...inputStyle, marginTop: 6 }} />
                  {!otp ? (
                    <button onClick={() => { if (aadhaarNum.length === 12 && mobile.length === 10) setOtp("sent") }} style={btnStyle("#c88010")}>Send OTP</button>
                  ) : (
                    <>
                      <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase", display: "block", marginTop: 10 }}>Enter OTP</label>
                      <input placeholder="6-digit OTP" style={{ ...inputStyle, marginTop: 6 }} />
                      <button onClick={() => simulate("Link")} style={btnStyle("#c88010")}>
                        {loading ? "Linking…" : "🔗 Link Mobile to Aadhaar"}
                      </button>
                    </>
                  )}
                </>
              )}

              {/* UPDATE AADHAAR */}
              {item.id === "update" && (
                <>
                  <p style={{ fontSize: 13, color: "#6a7a5a", marginBottom: 14 }}>Update your Aadhaar details (Name, DOB, Address) on UIDAI portal.</p>
                  <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase" }}>Aadhaar Number</label>
                  <input value={aadhaarNum} onChange={e => setNum(e.target.value.replace(/\D/g, "").slice(0, 12))} placeholder="XXXX XXXX XXXX" style={{ ...inputStyle, marginTop: 6 }} />
                  <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase", display: "block", marginTop: 4 }}>Field to Update</label>
                  <div style={{ display: "flex", gap: 8, marginBottom: 10, flexWrap: "wrap", marginTop: 6 }}>
                    {["Name", "DOB", "Address", "Gender"].map(f => (
                      <button key={f} style={{ borderRadius: 10, padding: "7px 14px", border: "1.5px solid #c8ddb0", background: "#fff", fontSize: 12, fontWeight: 700, color: "#3e4e26", cursor: "pointer" }}>{f}</button>
                    ))}
                  </div>
                  <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase" }}>Upload Supporting Document</label>
                  <div style={{ marginTop: 6, marginBottom: 10 }}>
                    <label style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 10, borderRadius: 12, border: "2px dashed #c8ddb0", padding: "16px", cursor: "pointer", background: "#f9fcf6" }}>
                      <span style={{ fontSize: 24 }}>📁</span>
                      <span style={{ fontSize: 13, fontWeight: 700, color: "#5a6e3a" }}>{file ? file.name : "Tap to upload document"}</span>
                      <input type="file" style={{ display: "none" }} accept="image/*,.pdf" onChange={e => setFile(e.target.files[0])} />
                    </label>
                  </div>
                  <button onClick={() => simulate("Update")} style={btnStyle()}>
                    {loading ? "Submitting…" : "✏️ Submit Update Request"}
                  </button>
                </>
              )}

              {/* VERIFY AADHAAR */}
              {item.id === "verify" && (
                <>
                  <p style={{ fontSize: 13, color: "#6a7a5a", marginBottom: 14 }}>Instantly verify any Aadhaar number via UIDAI's secure API.</p>
                  <label style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase" }}>Aadhaar Number to Verify</label>
                  <input value={aadhaarNum} onChange={e => setNum(e.target.value.replace(/\D/g, "").slice(0, 12))} placeholder="XXXX XXXX XXXX" style={{ ...inputStyle, marginTop: 6 }} />
                  <div style={{ background: "#eef7f0", borderRadius: 12, padding: "10px 12px", marginBottom: 14, fontSize: 11, color: "#1e6b40", fontWeight: 600 }}>
                    🔒 UIDAI certified verification — no data stored
                  </div>
                  <button onClick={() => simulate("Verify")} style={btnStyle("#2cb89a")}>
                    {loading ? "Verifying…" : "✅ Verify Aadhaar Now"}
                  </button>
                </>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  )
}

/* ─── small helpers ────────────────────────────────────────────────────────── */
function SectionHeader({ title, onViewAll }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "20px 20px 14px" }}>
      <p style={{ fontFamily: "'Nunito',sans-serif", fontSize: 18, fontWeight: 900, color: "#1a2420", margin: 0 }}>{title}</p>
      {onViewAll && (
        <button onClick={onViewAll} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 13, fontWeight: 800, color: "#8aab5c", fontFamily: "'Nunito',sans-serif" }}>View All</button>
      )}
    </div>
  )
}

function HandymanCard({ item, onClick }) {
  return (
    <div onClick={onClick} style={{ background: "#fff", borderRadius: 20, overflow: "hidden", display: "flex", flexDirection: "column", boxShadow: "0 4px 16px rgba(0,0,0,0.04)", border: "1px solid #f0ede5", cursor: "pointer", transition: "transform .15s" }}
      onMouseEnter={e => e.currentTarget.style.transform = "scale(1.02)"}
      onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}
    >
      <div style={{ background: item.color, height: 75, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 32 }}>{item.emoji}</div>
      <div style={{ padding: "10px 12px 14px", display: "flex", flexDirection: "column", alignItems: "center", background: "#fff" }}>
        <span style={{ fontFamily: "'Nunito',sans-serif", fontSize: 13, fontWeight: 900, color: "#1a2420", textAlign: "center", lineHeight: 1.2, marginBottom: 2 }}>{item.label}</span>
        <span style={{ fontSize: 10, fontWeight: 600, color: "#8a9a7a", textAlign: "center" }}>{item.sub}</span>
      </div>
    </div>
  )
}

function HandymanHorizontalCard({ item, onClick }) {
  return (
    <div onClick={onClick} style={{ background: "#fff", border: "1px solid #f0ede5", borderRadius: 22, padding: "12px", display: "flex", alignItems: "center", gap: 14, cursor: "pointer", width: "100%", boxShadow: "0 4px 16px rgba(0,0,0,0.03)", transition: "transform .14s" }}
      onMouseEnter={e => e.currentTarget.style.transform = "scale(1.01)"}
      onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}
    >
      <div style={{ width: 56, height: 56, borderRadius: 16, background: item.color, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, flexShrink: 0 }}>{item.emoji}</div>
      <div style={{ flex: 1 }}>
        <p style={{ fontFamily: "'Nunito',sans-serif", fontSize: 15, fontWeight: 900, color: "#1a2420", margin: "0 0 2px" }}>{item.label}</p>
        <p style={{ fontSize: 12, fontWeight: 600, color: "#8a9a7a", margin: 0 }}>{item.sub}</p>
      </div>
      {item.badge && <span style={{ background: item.color, color: item.accent, borderRadius: 12, padding: "6px 12px", fontSize: 11, fontWeight: 800, fontFamily: "'Nunito',sans-serif", flexShrink: 0 }}>{item.badge}</span>}
      {item.status && <div style={{ background: item.status === "linked" ? "#eef7f0" : item.color, borderRadius: 12, padding: "6px 12px", flexShrink: 0 }}><span style={{ fontSize: 11, fontWeight: 800, color: item.status === "linked" ? "#2cb89a" : item.accent }}>{item.status === "linked" ? "Linked" : "Link"}</span></div>}
    </div>
  )
}

/* ── Medicine card with Buy + Add to Cart ── */
function MedicineItemCard({ med, onBuy, onAddToCart, bought, inCart }) {
  const discountPct = med.originalPrice ? Math.round((1 - med.price / med.originalPrice) * 100) : null
  return (
    <div style={{ background: "#fff", borderRadius: 18, padding: "14px 16px", boxShadow: "0 2px 12px rgba(0,0,0,0.06)", border: "1px solid #f0ede5", display: "flex", alignItems: "center", gap: 14, marginBottom: 10 }}>
      <div style={{ width: 46, height: 46, borderRadius: 14, background: "#eef3e4", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, flexShrink: 0 }}>{med.emoji || "💊"}</div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontFamily: "'Nunito',sans-serif", fontSize: 14, fontWeight: 900, color: "#1a2420" }}>{med.name}</div>
        <div style={{ fontSize: 11, color: "#8a9a7a", marginTop: 2 }}>{med.dosage}</div>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 4 }}>
          <span style={{ fontWeight: 900, fontSize: 14, color: "#3e4e26" }}>₹{med.price}</span>
          {med.originalPrice && <span style={{ textDecoration: "line-through", fontSize: 11, color: "#bbb" }}>₹{med.originalPrice}</span>}
          {discountPct && <span style={{ background: "#eef7ec", color: "#2cb89a", fontSize: 10, fontWeight: 800, borderRadius: 8, padding: "2px 7px" }}>{discountPct}% off</span>}
        </div>
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 6, flexShrink: 0 }}>
        <button onClick={() => !bought && onBuy(med)} style={{
          background: bought ? "#e8f4f0" : "linear-gradient(135deg,#5a6e3a,#3e4e26)",
          color: bought ? "#2cb89a" : "#fff", border: "none", borderRadius: 10, padding: "7px 14px",
          fontSize: 11, fontWeight: 800, cursor: bought ? "default" : "pointer", fontFamily: "'Nunito',sans-serif"
        }}>{bought ? "✓ Ordered" : "Buy Now"}</button>
        <button onClick={() => onAddToCart(med)} style={{
          background: inCart ? "#fff3e8" : "#fff", color: inCart ? "#c88010" : "#3e4e26",
          border: `1.5px solid ${inCart ? "#c88010" : "#c8ddb0"}`, borderRadius: 10, padding: "6px 10px",
          fontSize: 10, fontWeight: 800, cursor: "pointer", fontFamily: "'Nunito',sans-serif"
        }}>{inCart ? "✓ In Cart 🛒" : "+ Add to Cart"}</button>
      </div>
    </div>
  )
}

/* ── Medicine detail bottom sheet ── */
function MedicineDetailSheet({ category, userMeds, onBuy, boughtSet, onAddToCart, cart, onClose }) {
  const isPrescription = category.id === "prescription"
  const isOtc = category.id === "otc"
  const staticMeds = isPrescription ? COMMON_PRESCRIPTION_MEDS : isOtc ? OTC_MEDS : []
  const savedMeds = isPrescription ? userMeds.map(m => ({ name: m.name, dosage: m.dosage || "", price: m.price || 99, originalPrice: m.price ? m.price * 2 : 198, emoji: "💊", fromDb: true, id: m.id })) : []
  const cartNames = new Set(cart.map(i => i.name))

  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, zIndex: 2000, background: "rgba(0,0,0,0.55)", display: "flex", alignItems: "flex-end", justifyContent: "center" }}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#fbf9f2", borderRadius: "26px 26px 0 0", width: "100%", maxWidth: 480, maxHeight: "88vh", overflowY: "auto", boxShadow: "0 -8px 44px rgba(0,0,0,0.18)" }}>
        <div style={{ padding: "18px 20px 0", position: "sticky", top: 0, background: "#fbf9f2", zIndex: 5, borderBottom: "1px solid #f0ede5" }}>
          <div style={{ width: 40, height: 4, borderRadius: 2, background: "#ddd", margin: "0 auto 14px" }} />
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
            <div>
              <div style={{ fontSize: 11, color: "#8a9a7a", fontWeight: 700, textTransform: "uppercase", marginBottom: 2 }}>Services</div>
              <p style={{ fontFamily: "'Nunito',sans-serif", fontSize: 18, fontWeight: 900, color: "#1a2420", margin: 0 }}>{category.emoji} {category.label}</p>
            </div>
            <button onClick={onClose} style={{ background: "#f0ede5", border: "none", borderRadius: 10, width: 36, height: 36, cursor: "pointer", fontSize: 14, color: "#888" }}>✕</button>
          </div>
          {isPrescription && savedMeds.length > 0 && (
            <div style={{ background: "#eef3e4", borderRadius: 14, padding: "8px 12px", marginBottom: 10, fontSize: 11, color: "#3e4e26", fontWeight: 700 }}>
              ✅ {savedMeds.length} medicine{savedMeds.length > 1 ? "s" : ""} from your Doc Analyser prescription
            </div>
          )}
          <div style={{ height: 10 }} />
        </div>
        <div style={{ padding: "14px 20px 40px" }}>
          {savedMeds.length > 0 && isPrescription && (
            <>
              <div style={{ fontSize: 11, fontWeight: 800, color: "#5a6e3a", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 10 }}>📋 Your Prescriptions</div>
              {savedMeds.map((m, i) => <MedicineItemCard key={`saved-${i}`} med={m} onBuy={onBuy} onAddToCart={onAddToCart} bought={boughtSet.has(m.name)} inCart={cartNames.has(m.name)} />)}
              <div style={{ fontSize: 11, fontWeight: 800, color: "#8a9a7a", textTransform: "uppercase", letterSpacing: 0.5, margin: "14px 0 10px" }}>🏪 Available in Store</div>
            </>
          )}
          {staticMeds.map((m, i) => {
            const isDup = savedMeds.some(s => s.name.toLowerCase() === m.name.toLowerCase())
            if (isDup) return null
            return <MedicineItemCard key={`static-${i}`} med={m} onBuy={onBuy} onAddToCart={onAddToCart} bought={boughtSet.has(m.name)} inCart={cartNames.has(m.name)} />
          })}
        </div>
      </div>
    </div>
  )
}

/* ── Full modal (View All) ── */
function ViewAllModal({ title, children, onClose }) {
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, zIndex: 2000, background: "rgba(0,0,0,0.55)", display: "flex", alignItems: "flex-end", justifyContent: "center" }}>
      <div onClick={e => e.stopPropagation()} style={{ background: "#fbf9f2", borderRadius: "26px 26px 0 0", width: "100%", maxWidth: 480, maxHeight: "88vh", overflowY: "auto", boxShadow: "0 -8px 44px rgba(0,0,0,0.18)" }}>
        <div style={{ padding: "18px 20px 0", position: "sticky", top: 0, background: "#fbf9f2", zIndex: 5, borderBottom: "1px solid #f0ede5" }}>
          <div style={{ width: 40, height: 4, borderRadius: 2, background: "#ddd", margin: "0 auto 14px" }} />
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
            <p style={{ fontFamily: "'Nunito',sans-serif", fontSize: 18, fontWeight: 900, color: "#1a2420", margin: 0 }}>{title}</p>
            <button onClick={onClose} style={{ background: "#f0ede5", border: "none", borderRadius: 10, width: 36, height: 36, cursor: "pointer", fontSize: 14, color: "#888" }}>✕</button>
