}

/* ─── MAIN PAGE ─────────────────────────────────────────────────────────────── */
export default function ServicesPage() {
  const [active, setActive] = useState("medicine")
  const [openCategory, setOpenCat] = useState(null)
  const [viewAllModal, setViewAll] = useState(null)
  const [aadhaarModal, setAadhaarMod] = useState(null)
  const [boughtSet, setBought] = useState(new Set())
  const [showCart, setShowCart] = useState(false)
  const [showCheckout, setCheckout] = useState(false)
  const [toast, setToast] = useState(null)
  const [userMeds, setUserMeds] = useState([])
  const [location, setLocation] = useState("Set Location")
  const { cart, addToCart, removeFromCart, updateQty, clearCart, totalItems, subtotal } = useCart()
  const user = auth.currentUser
  const locState = useLocation().state

  const showToast = msg => { setToast(msg); setTimeout(() => setToast(null), 2500) }

  useEffect(() => {
    // Switch to sale view if navigated from sale banner
    if (locState?.tab) setActive(locState.tab)
    if (user) {
      supabase.from("users").select("location").eq("firebase_uid", user.uid).single().then(({ data }) => {
        if (data?.location) setLocation(data.location)
      })
      supabase.from("users").select("id").eq("firebase_uid", user.uid).single().then(({ data: dbUser }) => {
        if (!dbUser) return
        supabase.from("medicines").select("id,name,dosage,instructions").eq("user_id", dbUser.id).order("created_at", { ascending: false }).limit(20).then(({ data: meds }) => {
          if (meds) setUserMeds(meds.map(m => ({ ...m, price: 99 })))
        })
      })
    }
  }, [user])

  const handleBuy = async (med) => {
    setBought(prev => new Set([...prev, med.name]))
    showToast(`🛒 ${med.name} ordered for ₹${med.price}!`)
    try {
      if (!user) return
      const { data: dbUser } = await supabase.from("users").select("id").eq("firebase_uid", user.uid).single()
      if (!dbUser) return
      await supabase.from("activities").insert({ user_id: dbUser.id, type: "medicine_purchase", title: `💊 ${med.name}`, description: `${med.name}${med.dosage ? ` ${med.dosage}` : ""} – Purchased from Services`, cost: med.price })
    } catch (e) { console.error(e) }
  }

  const handleAddToCart = (med) => {
    addToCart(med)
    showToast(`🛒 ${med.name} added to cart!`)
  }

  const handleCategoryClick = (item) => {
    if (item.id === "prescription" || item.id === "otc") setOpenCat(item)
  }

  return (
    <div style={{ fontFamily: "'Nunito Sans',sans-serif", background: "var(--cream)", minHeight: "100vh", paddingBottom: 100 }}>
      {/* ── Services Actions ── */}
      <div style={{ padding: "24px 20px 16px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <div style={{ fontSize: 22, fontWeight: 800, color: "#1a2420", fontFamily: "'Nunito',sans-serif" }}>Services Hub</div>
        <button onClick={handleUpdateLocation} style={{ display: "flex", alignItems: "center", gap: 8, background: "#fff", padding: "8px 14px", borderRadius: 30, border: "1px solid #f0ede5", cursor: "pointer", boxShadow: "0 2px 10px rgba(0,0,0,0.02)" }}>
          <span style={{ fontSize: 16 }}>📍</span>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-start" }}>
            <span style={{ fontSize: 10, fontWeight: 700, color: "var(--text-muted)", lineHeight: 1 }}>Location</span>
            <span style={{ fontSize: 13, fontWeight: 900, color: "var(--text-primary)", fontFamily: "'Nunito',sans-serif", maxWidth: 80, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{location}</span>
          </div>
        </button>
      </div>

      {/* ── Search Bar ── */}
      <div style={{ padding: "0 20px", marginBottom: 24 }}>
        <div style={{ background: "#f2efe7", borderRadius: 100, padding: "14px 20px", display: "flex", alignItems: "center", gap: 12 }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#8a9a7a" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
          <input
            type="text"
            placeholder="Search here for Services..."
            style={{ flex: 1, background: "transparent", border: "none", outline: "none", fontSize: 15, fontWeight: 700, fontFamily: "'Nunito Sans',sans-serif", color: "var(--text-primary)" }}
          />
          <div style={{ background: "#1a2420", borderRadius: "50%", width: 28, height: 28, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><line x1="4" y1="21" x2="4" y2="14"></line><line x1="4" y1="10" x2="4" y2="3"></line><line x1="12" y1="21" x2="12" y2="12"></line><line x1="12" y1="8" x2="12" y2="3"></line><line x1="20" y1="21" x2="20" y2="16"></line><line x1="20" y1="12" x2="20" y2="3"></line><line x1="1" y1="14" x2="7" y2="14"></line><line x1="9" y1="8" x2="15" y2="8"></line><line x1="17" y1="16" x2="23" y2="16"></line></svg>
          </div>
        </div>
      </div>

      {/* Promo Banner */}
      <div style={{ padding: "0 20px", marginBottom: 22 }}>
        <div style={{ borderRadius: 32, background: "linear-gradient(135deg,#425524,#2e3e15)", padding: "22px 22px", display: "flex", alignItems: "center", position: "relative", overflow: "hidden", boxShadow: "0 12px 30px rgba(66,85,36,0.2)" }}>
          <div style={{ position: "absolute", top: -20, right: -10, width: 140, height: 140, background: "rgba(255,255,255,0.04)", borderRadius: "40%", transform: "rotate(15deg)" }} />
          <div style={{ flex: 1, position: "relative", zIndex: 1 }}>
            <div style={{ background: "rgba(255,255,255,0.15)", color: "#fff", borderRadius: 20, padding: "4px 12px", fontSize: 10, fontWeight: 800, display: "inline-block", marginBottom: 10, letterSpacing: 0.5, textTransform: "uppercase" }}>Special Offer</div>
            <p style={{ fontFamily: "'Nunito',sans-serif", fontSize: 30, fontWeight: 900, color: "#fff", lineHeight: 1.1, margin: "0 0 4px" }}>30% OFF</p>
            <p style={{ fontSize: 12, fontWeight: 600, color: "rgba(255,255,255,0.7)", margin: "0 0 18px" }}>Limited Time*</p>
            <button style={{ background: "#fff", border: "none", borderRadius: 22, padding: "11px 18px", fontSize: 13, fontWeight: 900, color: "#1a2420", cursor: "pointer", display: "flex", alignItems: "center", gap: 10, width: 130 }}>
              Book Now <span style={{ background: "#f0ede5", borderRadius: "50%", width: 22, height: 22, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 10 }}>›</span>
            </button>
          </div>
          <div style={{ position: "relative", zIndex: 1 }}>
            <span style={{ fontSize: 68, filter: "drop-shadow(0 10px 20px rgba(0,0,0,0.2))" }}>👨‍⚕️</span>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ padding: "0 20px", marginBottom: 8, overflowX: "auto", scrollbarWidth: "none" }}>
        <div style={{ display: "inline-flex", gap: 10 }}>
          {TABS.map(t => (
            <button key={t.id} onClick={() => setActive(t.id)} style={{
