              background: active === t.id ? "#1a2420" : "#fff",
              border: active === t.id ? "1px solid #1a2420" : "1px solid #f0ede5",
              color: active === t.id ? "#fff" : "#1a2420",
              fontFamily: "'Nunito',sans-serif", fontSize: 14, fontWeight: 800, cursor: "pointer",
              whiteSpace: "nowrap", transition: "all 0.2s",
              boxShadow: active === t.id ? "0 8px 16px rgba(26,36,32,0.15)" : "0 2px 8px rgba(0,0,0,0.02)"
            }}>
