      <div key={active} style={{ animation: "fadeUp .28s ease both" }}>

        {/* ── MEDICINE + UTILITIES ── */}
        {(active === "medicine" || active === "utilities") && (
          <>
            <SectionHeader
              title={active === "medicine" ? "Popular Services" : "Utility Services"}
              onViewAll={() => setViewAll(active === "medicine" ? "popular" : "utilities")}
            />
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 12, padding: "0 20px" }}>
              {(active === "medicine" ? MEDICINE_CATEGORIES : UTILITY_ITEMS).map(item => (
                <HandymanCard key={item.id} item={item} onClick={() => handleCategoryClick(item)} />
              ))}
            </div>

            {/* Sale / Discounted section */}
            {active === "medicine" && (locState?.showSale || true) && (
              <>
                <SectionHeader title="🔥 Flash Sale – 50% Off" />
