                  {COMMON_PRESCRIPTION_MEDS.slice(0, 4).map(m => (
                    <MedicineItemCard key={m.name} med={m} onBuy={handleBuy} onAddToCart={handleAddToCart} bought={boughtSet.has(m.name)} inCart={cart.some(c => c.name === m.name)} />
